from pydantic import Field
from llama_index.core.workflow import Workflow, StartEvent, StopEvent, step, Event, Context

class RetrievalEvent(Event):
    query: str = Field(..., description="Original user query")
    nodes: list = Field(..., description="Retrieved nodes from vector store")
    retrieval_time_ms: float

class RerankEvent(Event):
    query: str
    nodes: list  # Reranked subset

class RAGWorkflow(Workflow):
    def __init__(self, index, top_k: int = 10, rerank_top_n: int = 5):
        super().__init__()
        self.retriever = index.as_retriever(similarity_top_k=top_k)
        self.reranker = SentenceTransformerRerank(
            model="cross-encoder/ms-marco-MiniLM-L-2-v2", top_n=rerank_top_n
        )

    @step
    async def retrieve(self, ctx: Context, ev: StartEvent) -> RetrievalEvent:
        import time
        start = time.time()
        nodes = await self.retriever.aretrieve(ev.query)
        await ctx.set("query", ev.query)
        return RetrievalEvent(query=ev.query, nodes=nodes,
                              retrieval_time_ms=(time.time()-start)*1000)

    @step
    async def rerank(self, ctx: Context, ev: RetrievalEvent) -> RerankEvent:
        reranked = self.reranker.postprocess_nodes(ev.nodes, query_str=ev.query)
        return RerankEvent(query=ev.query, nodes=reranked)

    @step
    async def synthesize(self, ctx: Context, ev: RerankEvent) -> StopEvent:
        from llama_index.core import get_response_synthesizer
        synth = get_response_synthesizer(response_mode="compact")
        response = await synth.asynthesize(ev.query, nodes=ev.nodes)
        return StopEvent(result={"response": str(response)})

@step
async def combine(self, ctx: Context,
                  ev: SearchResultEvent | AnalysisResultEvent) -> StopEvent | None:
    events = ctx.collect_events(ev, [SearchResultEvent, AnalysisResultEvent])
    if events is None:
        return None  # Wait — not all branches have completed yet
    search_result, analysis_result = events
    return StopEvent(result=f"Combined: {search_result.results}")
